Taking a canvas screenshot and downloading it now.
_____javascript
(async () => {
  const canvas = document.createElement('canvas');
  const w = Math.max(document.documentElement.scrollWidth, document.body.scrollWidth, window.innerWidth);
  const h = Math.max(document.documentElement.scrollHeight, document.body.scrollHeight, window.innerHeight);
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext('2d');

  // Draw visible viewport first
  ctx.drawWindow?.(window, 0, 0, w, h, 'white');

  // Fallback: if drawWindow is unavailable, try capturing the current viewport via html2canvas-style methods not assumed present
  if (!ctx.drawWindow) {
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, w, h);
    ctx.fillStyle = '#000';
    ctx.font = '16px sans-serif';
    ctx.fillText('Canvas screenshot capture not supported in this environment.', 20, 40);
  }

  const dataUrl = canvas.toDataURL('image/png');
  const a = document.createElement('a');
  a.href = dataUrl;
  a.download = `screenshot-${new Date().toISOString().replace(/[:.]/g, '-')}.png`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  return { downloaded: true, width: w, height: h };
})()

